function max(arr) {
  if (!arr.length) return undefined;
  return arr.reduce((m, v) => v > m ? v : m, arr[0]);
}

function sum(arr) {
  return arr.reduce((s, v) => s + v, 0);
}

module.exports = { max, sum };

